    }

    fn handleCsiIgnore(self: *Parser, byte: u8) ?InputEvent {
        if (byte >= 0x40 and byte <= 0x7e) self.state = .ground;
        return null;
    }

    fn dispatchCsi(self: *Parser, final: u8) InputEvent {
        const event = InputEvent{ .csi = .{
            .final = final,
            .intermediates = self.intermediates,
